// src/components/TelaEsterilizacao.jsx
import React, { useState, useEffect } from 'react'
import axios from 'axios'
import { toast } from 'react-toastify'

export default function TelaEsterilizacao() {
  const [codigo, setCodigo] = useState('')
  const [caixa, setCaixa]   = useState(null)
  const [alunoPin, setAlunoPin] = useState('')           // renomeado
  const [historico, setHistorico] = useState([])

  useEffect(() => {
    if (!caixa) return
    axios
      .get(`/api/movimentacoes/caixa/${caixa.id}`)
      .then(res => setHistorico(res.data))
      .catch(() => setHistorico([]))
  }, [caixa])

  const buscarCaixa = async () => {
    try {
      const res = await axios.get(`/api/caixas/codigo/${codigo}`)
      setCaixa(res.data)
      toast.success(`Caixa encontrada: ${res.data.nome}`)
    } catch {
      toast.error('Caixa não encontrada.')
      setCaixa(null)
      setHistorico([])
    }
  }

  const operar = async (tipo) => {
    if (!caixa) return toast.warn('Busque uma caixa primeiro.')
    if (!alunoPin) return toast.warn('Informe o PIN do aluno.')

    try {
      await axios.post(`/api/movimentacoes/${tipo}`, {
        caixa_id: caixa.id,
        aluno_pin: alunoPin                          // <-- envia PIN
      })
      toast.success(`${tipo === 'entrada' ? 'Entrada' : 'Saída'} registrada!`)
      const res = await axios.get(`/api/movimentacoes/caixa/${caixa.id}`)
      setHistorico(res.data)
    } catch {
      toast.error(`Erro ao registrar ${tipo}.`)
    }
  }

  return (
    <div className="max-w-xl mx-auto py-8">
      <h2 className="text-2xl font-bold mb-4">Controle de Esterilização</h2>

      {/* Busca da caixa */}
      <div className="flex gap-2 mb-4">
        <input
          type="text"
          placeholder="Código de barras"
          value={codigo}
          onChange={e => setCodigo(e.target.value)}
          className="flex-1 border px-3 py-2 rounded"
        />
        <button onClick={buscarCaixa} className="bg-blue-600 text-white px-4 py-2 rounded">
          Buscar
        </button>
      </div>

      {/* Dados da caixa */}
      {caixa && (
        <div className="mb-4 p-4 bg-gray-50 rounded">
          <p><strong>ID:</strong> {caixa.id}</p>
          <p><strong>Nome:</strong> {caixa.nome}</p>
        </div>
      )}

      {/* Operação */}
      {caixa && (
        <div className="flex gap-2 mb-6">
          <input
            type="text"
            placeholder="PIN do aluno"
            value={alunoPin}
            onChange={e => setAlunoPin(e.target.value.replace(/\D/g,'').slice(0,4))}
            className="flex-1 border px-3 py-2 rounded"
          />
          <button onClick={() => operar('entrada')} className="bg-green-600 text-white px-4 py-2 rounded">
            Entrada
          </button>
          <button onClick={() => operar('saida')} className="bg-red-600 text-white px-4 py-2 rounded">
            Saída
          </button>
        </div>
      )}

      {/* Histórico */}
      {historico.length > 0 ? (
        <table className="w-full table-auto border-collapse">
          <thead>
            <tr className="bg-gray-100">
              <th className="border px-2 py-1">Tipo</th>
              <th className="border px-2 py-1">Aluno</th>
              <th className="border px-2 py-1">Operador</th>
              <th className="border px-2 py-1">Data</th>
            </tr>
          </thead>
          <tbody>
            {historico.map(m => (
              <tr key={m.id} className="hover:bg-gray-50">
                <td className="border px-2 py-1">{m.tipo}</td>
                <td className="border px-2 py-1">{m.alunoNome}</td>
                <td className="border px-2 py-1">{m.operadorNome}</td>
                <td className="border px-2 py-1">
                  {new Date(m.criado_em).toLocaleString()}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      ) : (
        caixa && <p className="text-gray-500">Nenhuma movimentação registrada.</p>
      )}
    </div>
  )
}
